package com.example.nofiltercoffee; import android.os.*; import android.widget.*; import androidx.appcompat.app.*;
public class OrdersActivity extends AppCompatActivity{protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.simple_page);findViewById(R.id.btnBack).setOnClickListener(v->finish());((TextView)findViewById(R.id.txtTitle)).setText("My Orders");String data=UserSession.getOrders(this);StringBuilder sb=new StringBuilder();if(data.isEmpty())sb.append("No orders yet.");else{long now=System.currentTimeMillis();String[] rows=data.split(";;");for(int i=rows.length-1;i>=0;i--){String[] p=rows[i].split("\\|");if(p.length>=4){long pickup=Long.parseLong(p[2]);sb.append(pickup>now?"CURRENT ORDER\n":"PAST ORDER\n");sb.append("Order ID: ").append(p[0]).append("\nPickup: ").append(p[1]).append("\nTotal paid: Rs. ").append(p[3]).append("\n\n");}}}((TextView)findViewById(R.id.txtBody)).setText(sb.toString());}}
